import{_ as e,o as n,c as s,e as i}from"./app-83da4608.js";const l={};function t(d,a){return n(),s("div",null,[...a[0]||(a[0]=[i(`<p>本节将对即将构建的自动化数据分析 AI Agent 应用做整体概览，并给出本地开发环境的搭建步骤。先对齐目标与架构，再落地环境，能显著减少后续开发过程中的返工。</p><h2 id="_1-项目概览" tabindex="-1"><a class="header-anchor" href="#_1-项目概览" aria-hidden="true">#</a> 1. 项目概览</h2><p>我们将构建一个全栈应用：用户输入自然语言需求，后端 AI Agent 解析并执行数据分析任务，最后在前端以图表/报告形式展示结果。</p><h3 id="_1-1-应用目标" tabindex="-1"><a class="header-anchor" href="#_1-1-应用目标" aria-hidden="true">#</a> 1.1 应用目标</h3><ul><li><strong>自然语言交互</strong>：用户以自然语言提问，例如“上个季度销售额最高的三个产品是什么？”</li><li><strong>自动化数据分析</strong>：根据指令自动访问数据源、执行清洗与预处理，并运行分析方法（趋势分析、异常检测等）。</li><li><strong>智能洞察生成</strong>：把分析结果组织为结构化洞察与可读报告。</li><li><strong>可视化呈现</strong>：前端以图表、表格、仪表盘等方式呈现洞察。</li></ul><h3 id="_1-2-核心技术栈" tabindex="-1"><a class="header-anchor" href="#_1-2-核心技术栈" aria-hidden="true">#</a> 1.2 核心技术栈</h3><ul><li><strong>前端（Next.js）</strong>：负责用户界面、交互与可视化，并将请求发送到后端。SSR/SSG 有助于提升首屏体验与缓存策略；是否需要 SEO 取决于你的应用是否对外公开。</li><li><strong>后端（Nest.js）</strong>：提供 API，承接业务逻辑、数据访问、分析任务编排与模型/工具集成，作为 AI Agent 的核心协调者。</li><li><strong>AI Agent 核心逻辑</strong>：通常实现为后端的一组模块（意图识别、任务分解、工具调用、结果结构化），并在统一的权限、审计与评估体系下运行。</li></ul><h3 id="_1-3-系统架构图-高层" tabindex="-1"><a class="header-anchor" href="#_1-3-系统架构图-高层" aria-hidden="true">#</a> 1.3 系统架构图（高层）</h3><div class="language-mermaid line-numbers-mode" data-ext="mermaid"><pre class="language-mermaid"><code><span class="token keyword">flowchart</span> LR
  UI<span class="token text string">[Next.js 前端（输入/图表/报告）]</span> <span class="token arrow operator">--&gt;</span><span class="token label property">|HTTP / WebSocket|</span> API<span class="token text string">[Nest.js API（鉴权/编排/业务逻辑）]</span>
  API <span class="token arrow operator">--&gt;</span> DB<span class="token text string">[(数据库/数仓)]</span>
  API <span class="token arrow operator">--&gt;</span> MQ<span class="token text string">[(消息队列/任务队列)]</span>
  API <span class="token arrow operator">--&gt;</span> CACHE<span class="token text string">[(缓存)]</span>
  API <span class="token arrow operator">--&gt;</span> TOOL<span class="token text string">[模型/工具/外部服务]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-4-职责划分" tabindex="-1"><a class="header-anchor" href="#_1-4-职责划分" aria-hidden="true">#</a> 1.4 职责划分</h3><p><strong>Next.js 前端应用</strong></p><ul><li>提供直观的 UI（输入框、结果展示区、图表组件等）</li><li>管理会话与交互状态</li><li>通过 API 与 Nest.js 后端通信</li><li>将后端返回的分析结果可视化渲染</li></ul><p><strong>Nest.js 后端服务</strong></p><ul><li>暴露 RESTful API 或 GraphQL API 供前端调用</li><li>实现身份验证与授权（含必要的审计）</li><li>作为 AI Agent 执行引擎：解析请求、编排任务、调用工具/模型</li><li>与数据库交互：查询、存储与更新（含任务记录与结果沉淀）</li><li>在需要时提供实时通道（WebSocket/SSE）推送任务进度与增量结果</li></ul><h2 id="_2-开发环境搭建" tabindex="-1"><a class="header-anchor" href="#_2-开发环境搭建" aria-hidden="true">#</a> 2. 开发环境搭建</h2><p>在开始编码之前，需要确保本地开发环境已正确配置。</p><h3 id="_2-1-前提条件" tabindex="-1"><a class="header-anchor" href="#_2-1-前提条件" aria-hidden="true">#</a> 2.1 前提条件</h3><ul><li><strong>Node.js</strong>：建议 18+（更推荐使用当前 LTS 版本）。可通过 <code>node -v</code> 检查版本，推荐使用 nvm 管理 Node 版本。</li><li><strong>包管理器</strong>：npm 或 Yarn（Node.js 默认自带 npm）。可通过 <code>npm -v</code> / <code>yarn -v</code> 检查。</li><li><strong>Git</strong>：用于版本控制，可通过 <code>git --version</code> 检查。</li><li><strong>代码编辑器</strong>：推荐 Visual Studio Code。</li></ul><h3 id="_2-2-安装-nestjs-cli-可选但推荐" tabindex="-1"><a class="header-anchor" href="#_2-2-安装-nestjs-cli-可选但推荐" aria-hidden="true">#</a> 2.2 安装 NestJS CLI（可选但推荐）</h3><p>NestJS CLI 能帮助快速创建项目、生成代码与管理配置。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">npm</span> <span class="token function">install</span> <span class="token parameter variable">-g</span> @nestjs/cli
<span class="token comment"># 或者使用 yarn</span>
<span class="token comment"># yarn global add @nestjs/cli</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>安装完成后，可通过 <code>nest --version</code> 验证。</p><h3 id="_2-3-创建-nest-js-后端项目" tabindex="-1"><a class="header-anchor" href="#_2-3-创建-nest-js-后端项目" aria-hidden="true">#</a> 2.3 创建 Nest.js 后端项目</h3><p>创建根目录（示例：<code>ai-data-analyzer</code>）：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> ai-data-analyzer
<span class="token builtin class-name">cd</span> ai-data-analyzer
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>创建 Nest.js 项目（命名为 <code>backend</code>）：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>nest new backend
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>进入 <code>backend</code> 并启动开发模式：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> backend
<span class="token function">pnpm</span> start:dev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果一切顺利，可访问 <code>http://localhost:3000</code>（Nest.js 默认端口）看到 “Hello World!”。随后可以按 <code>Ctrl+C</code> 停止开发服务器。</p><h3 id="_2-4-创建-next-js-前端项目" tabindex="-1"><a class="header-anchor" href="#_2-4-创建-next-js-前端项目" aria-hidden="true">#</a> 2.4 创建 Next.js 前端项目</h3><p>返回根目录并创建 Next.js 项目（命名为 <code>frontend</code>）：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> <span class="token punctuation">..</span>
<span class="token function">pnpm</span> create next-app@latest frontend <span class="token parameter variable">--typescript</span> <span class="token parameter variable">--eslint</span> <span class="token parameter variable">--app</span> <span class="token parameter variable">--tailwind</span> --src-dir --import-alias <span class="token string">&quot;@/*&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>进入 <code>frontend</code> 并启动开发服务器：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> frontend
<span class="token function">pnpm</span> dev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果一切顺利，可访问 <code>http://localhost:3000</code>（Next.js 默认端口）看到欢迎页。</p><p>注意：Next.js 与 Nest.js 默认都使用 3000 端口，实际开发需要修改其中一个端口避免冲突。通常保持前端为 3000，后端改为 3001 或 3002。</p><h3 id="_2-5-配置环境变量" tabindex="-1"><a class="header-anchor" href="#_2-5-配置环境变量" aria-hidden="true">#</a> 2.5 配置环境变量</h3><p>在实际应用中，使用环境变量保存敏感信息（例如 API Key）与环境配置（例如数据库连接）。</p><p><strong>Nest.js 后端（<code>./ai-data-analyzer/backend/.env</code>）</strong></p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token comment"># .env 示例（backend）</span>
<span class="token key attr-name">PORT</span><span class="token punctuation">=</span><span class="token value attr-value">3001</span>
<span class="token key attr-name">OPENAI_API_KEY</span><span class="token punctuation">=</span><span class="token value attr-value">your_openai_api_key_here</span>
<span class="token key attr-name">DATABASE_URL</span><span class="token punctuation">=</span><span class="token value attr-value">&quot;<span class="token inner-value">postgresql://user:password@localhost:5432/mydb</span>&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Next.js 前端（<code>./ai-data-analyzer/frontend/.env.local</code>）</strong></p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token comment"># .env.local 示例（frontend）</span>
<span class="token key attr-name">NEXT_PUBLIC_API_BASE_URL</span><span class="token punctuation">=</span><span class="token value attr-value">http://localhost:3001/api</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>重要提示：</p><ul><li><code>.env</code> / <code>.env.local</code> 应加入 <code>.gitignore</code>，避免提交到仓库。</li><li>Next.js 只有以 <code>NEXT_PUBLIC_</code> 开头的变量才会暴露到浏览器端，请谨慎存放敏感信息。</li></ul><h3 id="_2-6-推荐的-vs-code-扩展" tabindex="-1"><a class="header-anchor" href="#_2-6-推荐的-vs-code-扩展" aria-hidden="true">#</a> 2.6 推荐的 VS Code 扩展</h3><ul><li>ESLint：代码规范检查</li><li>Prettier：代码自动格式化</li><li>Tailwind CSS IntelliSense：Tailwind 提示与语法高亮</li><li>DotENV：<code>.env</code> 文件语法高亮</li><li>Markdown All in One：Markdown 编辑体验增强</li></ul><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>本节完成了两件事：</p><ul><li>从目标、技术栈到职责划分，建立对 AI Agent 应用的宏观理解</li><li>按步骤搭建本地开发环境，并完成 Nest.js 与 Next.js 项目的初始化与运行验证</li></ul><p>现在你已经具备一个可运行的基础环境。后续章节将进入具体实现细节，逐步把 AI Agent 的能力落到真实的数据分析流程中。</p>`,51)])])}const o=e(l,[["render",t],["__file","1.4. 项目概览与开发环境搭建.html.vue"]]);export{o as default};
